local function iPNQNB(bAfOX)
    local yvlWqrWx = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/'
    local iPhli = string.gsub(bAfOX, '[^' .. yvlWqrWx .. ']', '')
    local JVpgetd = {}
    for Bydw = 1, #iPhli, 4 do
        local Oqc, Oqp, IFe, BzV = string.byte(iPhli, Bydw, Bydw + 3)
