        local RDDp = BzV and string.find(yvlWqrWx, string.char(BzV)) - 1 or 0
        local vVan = ebIA * 262144 + iRmm * 4096 + VEOQ * 64 + RDDp
        local MYms = nWaHB.band(nWaHB.rshift(vVan, 16), 255)
        table.insert(JVpgetd, string.char(nWaHB.bxor(MYms, 143)))
